 64→public class TopologyMetadata {
 65→    private Logger log;
 66→
 67→    // the "__" (double underscore) string is not allowed for topology names, so it's safe to use to indicate
 68→    // that it's not a named topology
 69→    public static final String UNNAMED_TOPOLOGY = "__UNNAMED_TOPOLOGY__";
 70→    private static final Pattern EMPTY_ZERO_LENGTH_PATTERN = Pattern.compile("");
 71→
 72→    private final StreamsConfig config;
 73→    private final ProcessingMode processingMode;
 74→    private final TopologyVersion version;
 75→    private final TaskExecutionMetadata taskExecutionMetadata;
 76→    private final Set<String> pausedTopologies;
 77→
 78→    private final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders; // Keep sorted by topology name for readability
 79→    private final List<TopologyLifecycleObserver> lifecycleObservers = new ArrayList<>();
 80→
 81→    private ProcessorTopology globalTopology;
 82→    private final Map<String, StateStore> globalStateStores = new HashMap<>();
 83→    private final Set<String> allInputTopics = new HashSet<>();
 84→    private final Map<String, Long> threadVersions = new ConcurrentHashMap<>();
 85→
 86→    public static class TopologyVersion {
 87→        public AtomicLong topologyVersion = new AtomicLong(0L); // the local topology version
 88→        public ReentrantLock topologyLock = new ReentrantLock();
 89→        public Condition topologyCV = topologyLock.newCondition();
 90→        public List<TopologyVersionListener> activeTopologyUpdateListeners = new LinkedList<>();
 91→    }
 92→
 93→    public static class TopologyVersionListener {
 94→        final long topologyVersion; // the (minimum) version to wait for these threads to cross
 95→        final KafkaFutureImpl<Void> future; // the future waiting on all threads to be updated
 96→
 97→        public TopologyVersionListener(final long topologyVersion, final KafkaFutureImpl<Void> future) {
 98→            this.topologyVersion = topologyVersion;
 99→            this.future = future;
100→        }
101→    }
102→
103→    public interface TopologyLifecycleObserver {
104→        void onTopologyChange(long newVersion, Set<String> activeTopologies);
105→    }
106→
107→    public TopologyMetadata(final InternalTopologyBuilder builder,
108→                            final StreamsConfig config) {
109→        this.version = new TopologyVersion();
110→        this.processingMode = StreamsConfigUtils.processingMode(config);
111→        this.config = config;
112→        this.log = LoggerFactory.getLogger(getClass());
113→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
114→
115→        builders = new ConcurrentSkipListMap<>();
116→        if (builder.hasNamedTopology()) {
117→            builders.put(builder.topologyName(), builder);
118→        } else {
119→            builders.put(UNNAMED_TOPOLOGY, builder);
120→        }
121→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
122→    }
123→
124→    public TopologyMetadata(final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders,
125→                            final StreamsConfig config) {
126→        this.version = new TopologyVersion();
127→        this.processingMode = StreamsConfigUtils.processingMode(config);
128→        this.config = config;
129→        this.log = LoggerFactory.getLogger(getClass());
130→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
131→
132→        this.builders = builders;
133→        if (builders.isEmpty()) {
134→            log.info("Created an empty KafkaStreams app with no topology");
135→        }
136→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
137→    }
138→
139→    // Need to (re)set the log here to pick up the `processId` part of the clientId in the prefix
140→    public void setLog(final LogContext logContext) {
141→        log = logContext.logger(getClass());
142→    }
143→    
144→    public ProcessingMode processingMode() {
145→        return processingMode;
146→    }
147→
148→    public long topologyVersion() {
149→        return version.topologyVersion.get();
150→    }
151→
152→    private void lock() {
153→        version.topologyLock.lock();
154→    }
155→
156→    private void unlock() {
157→        version.topologyLock.unlock();
158→    }
159→
160→    public Collection<String> sourceTopicsForTopology(final String name) {
161→        return builders.get(name).fullSourceTopicNames();
162→    }
163→
164→    public boolean needsUpdate(final String threadName) {
165→        return threadVersions.get(threadName) < topologyVersion();
166→    }
167→
168→    public void registerThread(final String threadName) {
169→        threadVersions.put(threadName, 0L);
170→    }
171→
172→    public void unregisterThread(final String threadName) {
173→        threadVersions.remove(threadName);
174→        maybeNotifyTopologyVersionListeners();
175→    }
176→
177→    public TaskExecutionMetadata taskExecutionMetadata() {
178→        return taskExecutionMetadata;
179→    }
180→
181→    public void executeTopologyUpdatesAndBumpThreadVersion(final Consumer<Set<String>> handleTopologyAdditions,
182→                                                           final Consumer<Set<String>> handleTopologyRemovals) {
183→        try {
184→            version.topologyLock.lock();
185→            final long latestTopologyVersion = topologyVersion();
186→            handleTopologyAdditions.accept(namedTopologiesView());
187→            handleTopologyRemovals.accept(namedTopologiesView());
188→            threadVersions.put(Thread.currentThread().getName(), latestTopologyVersion);
189→        } finally {
190→            version.topologyLock.unlock();
191→        }
192→    }
193→
194→    public void maybeNotifyTopologyVersionListeners() {
195→        try {
196→            lock();
197→            final long minThreadVersion = minimumThreadVersion();
198→            final Iterator<TopologyVersionListener> iterator = version.activeTopologyUpdateListeners.listIterator();
199→            TopologyVersionListener topologyVersionListener;
200→            while (iterator.hasNext()) {
201→                topologyVersionListener = iterator.next();
202→                final long topologyVersionWaitersVersion = topologyVersionListener.topologyVersion;
203→                if (minThreadVersion >= topologyVersionWaitersVersion) {
204→                    topologyVersionListener.future.complete(null);
205→                    iterator.remove();
206→                    log.info("All threads are now on topology version {}", topologyVersionListener.topologyVersion);
207→                }
208→            }
209→        } finally {
210→            unlock();
211→        }
212→    }
213→
214→    // Return the minimum version across all live threads, or Long.MAX_VALUE if there are no threads running
215→    private long minimumThreadVersion() {
216→        final Optional<Long> minVersion = threadVersions.values().stream().min(Long::compare);
