284→    public void registerAndBuildNewTopology(final KafkaFutureImpl<Void> future, final InternalTopologyBuilder newTopologyBuilder) {
285→        try {
286→            lock();
287→            buildAndVerifyTopology(newTopologyBuilder);
288→            log.info("New NamedTopology {} passed validation and will be added, old topology version is {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
289→            version.topologyVersion.incrementAndGet();
290→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), future));
291→            builders.put(newTopologyBuilder.topologyName(), newTopologyBuilder);
292→            wakeupThreads();
293→            notifyLifecycleObservers();
294→            log.info("Added NamedTopology {} and updated topology version to {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
295→        } catch (final Throwable throwable) {
296→            log.error("Failed to add NamedTopology {}, please retry the operation.", newTopologyBuilder.topologyName());
297→            future.completeExceptionally(throwable);
298→        } finally {
299→            unlock();
300→        }
301→    }
