331→    public KafkaFuture<Void> unregisterTopology(final KafkaFutureImpl<Void> removeTopologyFuture,
332→                                                final String topologyName) {
333→        try {
334→            lock();
335→            log.info("Beginning removal of NamedTopology {}, old topology version is {}", topologyName, version.topologyVersion.get());
336→            version.topologyVersion.incrementAndGet();
337→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), removeTopologyFuture));
338→            final InternalTopologyBuilder removedBuilder = builders.remove(topologyName);
339→            removedBuilder.fullSourceTopicNames().forEach(allInputTopics::remove);
340→            removedBuilder.allSourcePatternStrings().forEach(allInputTopics::remove);
341→            notifyLifecycleObservers();
342→            log.info("Finished removing NamedTopology {}, topology version was updated to {}", topologyName, version.topologyVersion.get());
343→        } catch (final Throwable throwable) {
344→            log.error("Failed to remove NamedTopology {}, please retry.", topologyName);
345→            removeTopologyFuture.completeExceptionally(throwable);
346→        } finally {
347→            unlock();
348→        }
349→        return removeTopologyFuture;
350→    }
