339→    public UUID initializeProcessId() {
340→        if (!hasPersistentStores) {
341→            final UUID processId = UUID.randomUUID();
342→            log.info("Created new process id: {}", processId);
343→            return processId;
344→        }
345→
346→        if (!lockStateDirectory()) {
347→            log.error("Unable to obtain lock as state directory is already locked by another process");
348→            throw new StreamsException(String.format("Unable to initialize state, this can happen if multiple instances of " +
349→                                           "Kafka Streams are running in the same state directory " +
350→                                           "(current state directory is [%s]", stateDir.getAbsolutePath()));
351→        }
352→
353→        final File processFile = new File(stateDir, PROCESS_FILE_NAME);
354→        final ObjectMapper mapper = new ObjectMapper();
355→
356→        try {
357→            if (processFile.exists()) {
358→                try {
359→                    final StateDirectoryProcessFile processFileData = mapper.readValue(processFile, StateDirectoryProcessFile.class);
360→                    log.info("Reading UUID from process file: {}", processFileData.processId);
361→                    if (processFileData.processId != null) {
362→                        return processFileData.processId;
363→                    }
364→                } catch (final Exception e) {
365→                    log.warn("Failed to read json process file", e);
366→                }
367→            }
368→
369→            final StateDirectoryProcessFile processFileData = new StateDirectoryProcessFile(UUID.randomUUID());
370→            log.info("No process id found on disk, got fresh process id {}", processFileData.processId);
371→
372→            mapper.writeValue(processFile, processFileData);
373→            return processFileData.processId;
374→        } catch (final IOException e) {
375→            log.error("Unable to read/write process file due to unexpected exception", e);
376→            throw new ProcessorStateException(e);
377→        }
378→    }
