716→    private void cleanStateAndTaskDirectoriesCalledByUser() throws Exception {
717→        if (!lockedTasksToOwner.isEmpty()) {
718→            log.warn("Found some still-locked task directories when user requested to cleaning up the state, "
719→                + "since Streams is not running any more these will be ignored to complete the cleanup");
720→        }
721→        taskOffsetSums.clear();
722→        final AtomicReference<Exception> firstException = new AtomicReference<>();
723→        for (final TaskDirectory taskDir : listAllTaskDirectories()) {
724→            final String dirName = taskDir.file().getName();
725→            final TaskId id = parseTaskDirectoryName(dirName, taskDir.namedTopology());
726→            try {
727→                log.info("{} Deleting task directory {} for {} as user calling cleanup.",
728→                    logPrefix(), dirName, id);
729→
730→                if (lockedTasksToOwner.containsKey(id)) {
731→                    log.warn("{} Task {} in state directory {} was still locked by {}",
732→                        logPrefix(), dirName, id, lockedTasksToOwner.get(id));
733→                }
734→                Utils.delete(taskDir.file());
735→            } catch (final IOException exception) {
736→                log.error(
737→                    String.format("%s Failed to delete task directory %s for %s with exception:",
738→                        logPrefix(), dirName, id),
739→                    exception
740→                );
741→                firstException.compareAndSet(null, exception);
742→            }
743→        }
744→
745→        firstException.compareAndSet(null, maybeCleanEmptyNamedTopologyDirs(false));
746→
747→        final Exception exception = firstException.get();
748→        if (exception != null) {
749→            throw exception;
750→        }
751→    }
