753→    /**
754→     * List all of the task directories that are non-empty
755→     * @return The list of all the non-empty local directories for stream tasks
756→     */
757→    List<TaskDirectory> listNonEmptyTaskDirectories() {
758→        return listTaskDirectories(pathname -> {
759→            if (!pathname.isDirectory() || !TASK_DIR_PATH_NAME.matcher(pathname.getName()).matches()) {
760→                return false;
761→            } else {
762→                return !taskDirIsEmpty(pathname);
763→            }
764→        });
765→    }
