767→    /**
768→     * List all of the task directories along with their parent directory if they belong to a named topology
769→     * @return The list of all the existing local directories for stream tasks
770→     */
771→    List<TaskDirectory> listAllTaskDirectories() {
772→        return listTaskDirectories(pathname -> pathname.isDirectory() && TASK_DIR_PATH_NAME.matcher(pathname.getName()).matches());
