775→    private List<TaskDirectory> listTaskDirectories(final FileFilter filter) {
776→        final List<TaskDirectory> taskDirectories = new ArrayList<>();
777→        if (hasPersistentStores && stateDir.exists()) {
778→            if (hasNamedTopologies) {
779→                for (final File namedTopologyDir : listNamedTopologyDirs()) {
780→                    final String namedTopology = parseNamedTopologyFromDirectory(namedTopologyDir.getName());
781→                    final File[] taskDirs = namedTopologyDir.listFiles(filter);
782→                    if (taskDirs != null) {
783→                        taskDirectories.addAll(Arrays.stream(taskDirs)
784→                            .map(f -> new TaskDirectory(f, namedTopology)).collect(Collectors.toList()));
785→                    }
786→                }
787→            } else {
788→                final File[] taskDirs =
789→                    stateDir.listFiles(filter);
790→                if (taskDirs != null) {
791→                    taskDirectories.addAll(Arrays.stream(taskDirs)
792→                                               .map(f -> new TaskDirectory(f, null)).collect(Collectors.toList()));
793→                }
794→            }
795→        }
796→
797→        return taskDirectories;
798→    }
799→
800→    private List<File> listNamedTopologyDirs() {
801→        final File[] namedTopologyDirectories = stateDir.listFiles(f -> f.getName().startsWith("__") &&  f.getName().endsWith("__"));
802→        return namedTopologyDirectories != null ? Arrays.asList(namedTopologyDirectories) : Collections.emptyList();
803→    }
804→
805→    private String parseNamedTopologyFromDirectory(final String dirName) {
806→        return dirName.substring(2, dirName.length() - 2);
807→    }
