 69→    public PunctuationSchedule next(final long currTimestamp) {
 70→        long nextPunctuationTime = timestamp + interval;
 71→        if (currTimestamp >= nextPunctuationTime) {
 72→            // we missed one or more punctuations
 73→            // avoid scheduling a new punctuations immediately, this can happen:
 74→            // - when using STREAM_TIME punctuation and there was a gap i.e., no data was
 75→            //   received for at least 2*interval
 76→            // - when using WALL_CLOCK_TIME and there was a gap i.e., punctuation was delayed for at least 2*interval (GC pause, overload, ...)
 77→            final long intervalsMissed = (currTimestamp - timestamp) / interval;
 78→            nextPunctuationTime = timestamp + (intervalsMissed + 1) * interval;
 79→        }
 80→
 81→        final PunctuationSchedule nextSchedule = new PunctuationSchedule(value, nextPunctuationTime, interval, punctuator, cancellable);
 82→
 83→        cancellable.setSchedule(nextSchedule);
 84→
 85→        return nextSchedule;
 86→    }
